  useEffect(() => {
    if (account && !formData.destinationAddress) {
      setFormData(prev => ({ ...prev, destinationAddress: account }));
    }
  }, [account, formData.destinationAddress]);

  const availableNetworks = getAvailableNetworks();
  const sourceTokens = getAvailableSourceTokens(formData.sourceNetwork);
  const destinationNetworks = formData.sourceNetwork && formData.sourceToken 
    ? getAvailableDestinationNetworks(formData.sourceNetwork, sourceTokens.find(t => t.symbol === formData.sourceToken)?.address)
    : [];
  const destinationTokens = formData.sourceNetwork && formData.sourceToken && formData.destinationNetwork
    ? getAvailableDestinationTokens(formData.sourceNetwork, sourceTokens.find(t => t.symbol === formData.sourceToken)?.address, formData.destinationNetwork)
    : [];

  return (
