                value={formData.amount}
                onChange={(e) => handleInputChange('amount', e.target.value)}
                placeholder="0.0"
                step="0.000001"
                className={`input-field w-full ${errors.amount ? 'border-error-500' : ''}`}
              />
              {errors.amount && (
                <p className="text-error-400 text-sm mt-1">{errors.amount}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Reward for Assistant (Optional)
              </label>
              <input
                type="number"
                value={formData.reward}
                onChange={(e) => handleInputChange('reward', e.target.value)}
                placeholder="0.0"
                step="0.000001"
                className="input-field w-full"
              />
              <p className="text-secondary-400 text-sm mt-1">
                Optional reward to incentivize assistants to process your transfer faster
              </p>
            </div>
          </div>

          {/* Bridge Operation Info */}
          {bridgeOperation && (
            <div className="bg-info-900/50 border border-info-700 rounded-lg p-4">
              <div className="flex items-center space-x-2">
                <div className="w-4 h-4 bg-info-500 rounded-full"></div>
                <h3 className="text-info-400 font-medium">Bridge Operation</h3>
              </div>
              <p className="text-info-300 text-sm mt-1">
                {bridgeOperation === 'expatriation' 
                  ? `Expatriation: ${formData.sourceNetwork} → ${formData.destinationNetwork} (Export bridge)`
                  : `Repatriation: ${formData.sourceNetwork} → ${formData.destinationNetwork} (Import bridge)`
                }
              </p>
              {selectedBridgeInstance && (
                <p className="text-info-300 text-sm mt-1">
                  Bridge: {selectedBridgeInstance.description}
                </p>
              )}
            </div>
          )}



          {/* Receiver's Address */}
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Receiver's Address
            </label>
            <input
              type="text"
              value={formData.destinationAddress}
              onChange={(e) => handleInputChange('destinationAddress', e.target.value)}
              placeholder="0x..."
              className={`input-field w-full font-mono ${errors.destinationAddress ? 'border-error-500' : ''}`}
            />
            {errors.destinationAddress && (
              <p className="text-error-400 text-sm mt-1">{errors.destinationAddress}</p>
            )}
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={isLoading || !isConnected}
            className="w-full btn-primary py-3 text-lg font-medium disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isLoading ? (
              <div className="flex items-center justify-center space-x-2">
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                <span>Processing Transfer...</span>
              </div>
            ) : (
              'Initiate Transfer'
            )}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default BridgeForm;
